#ifndef TRANSLATED_PARTICLE_FILTER_KERNELS
#define TRANSLATED_PARTICLE_FILTER_KERNELS

#pragma OPENCL EXTENSION cl_khr_fp64 : enable

#define PF_PI 3.1415926535897932
#define PF_M 2147483647L
#define PF_A 1103515245
#define PF_C 12345

inline double pf_roundDouble(double value) {
    int newValue = (int)(value);
    if (value - newValue < 0.5)
        return (double)newValue;
    else
        return (double)newValue;
}

inline double pf_randu(__global int *seed, int index) {
    int num = PF_A * seed[index] + PF_C;
    seed[index] = num % PF_M;
    return fabs(seed[index] / ((double)PF_M));
}

inline double pf_randn(__global int *seed, int index) {
    double u = pf_randu(seed, index);
    double v = pf_randu(seed, index);
    double cosine = cos(2.0 * PF_PI * v);
    double rt = -2.0 * log(u);
    return sqrt(rt) * cosine;
}

inline int pf_findIndex(__global double *CDF, int lengthCDF, double value) {
    int index = -1;
    for (int x = 0; x < lengthCDF; x++) {
        if (CDF[x] >= value) {
            index = x;
            break;
        }
    }
    if (index == -1)
        return lengthCDF - 1;
    return index;
}

__kernel void likelihood_kernel(__global double *arrayX,
                                __global double *arrayY,
                                __global double *xj,
                                __global double *yj,
                                __global double *CDF,
                                __global int *ind,
                                __global int *objxy,
                                __global double *likelihood,
                                __global unsigned char *I,
                                __global double *u,
                                __global double *weights,
                                int Nparticles,
                                int countOnes,
                                int max_size,
                                int k,
                                int IszY,
                                int Nfr,
                                __global int *seed,
                                __global double *partial_sums,
                                __local double *buffer) {
    int x = get_global_id(0);
    (void)CDF;
    (void)u;
    (void)buffer;

    if (x >= Nparticles)
        return;

    arrayX[x] = xj[x] + 1.0 + 5.0 * pf_randn(seed, x);
    arrayY[x] = yj[x] + -2.0 + 2.0 * pf_randn(seed, x);

    double like = 0.0;
    for (int y = 0; y < countOnes; y++) {
        int indX = (int)pf_roundDouble(arrayX[x]) + objxy[y * 2 + 1];
        int indY = (int)pf_roundDouble(arrayY[x]) + objxy[y * 2];
        int idx = abs(indX * IszY * Nfr + indY * Nfr + k);
        if (idx >= max_size)
            idx = 0;
        ind[x * countOnes + y] = idx;
        like += ((double)((int)I[idx] - 100) * (double)((int)I[idx] - 100) -
                 (double)((int)I[idx] - 228) * (double)((int)I[idx] - 228)) / 50.0;
    }
    like = like / ((double)countOnes);
    likelihood[x] = like;
    weights[x] = weights[x] * exp(like);
    partial_sums[x] = weights[x];
}

__kernel void sum_kernel(__global double *partial_sums, int Nparticles) {
    int gid = get_global_id(0);
    if (gid != 0)
        return;

    double sumWeights = 0.0;
    for (int x = 0; x < Nparticles; x++) {
        sumWeights += partial_sums[x];
    }
    partial_sums[0] = sumWeights;
}

__kernel void normalize_weights_kernel(__global double *weights,
                                       int Nparticles,
                                       __global double *partial_sums,
                                       __global double *CDF,
                                       __global double *u,
                                       __global int *seed) {
    int gid = get_global_id(0);
    if (gid != 0)
        return;

    double sumWeights = partial_sums[0];
    if (sumWeights == 0.0)
        sumWeights = 1.0;

    for (int x = 0; x < Nparticles; x++) {
        weights[x] = weights[x] / sumWeights;
    }

    if (Nparticles > 0) {
        CDF[0] = weights[0];
        for (int x = 1; x < Nparticles; x++) {
            CDF[x] = weights[x] + CDF[x - 1];
        }

        double u1 = (1.0 / (double)Nparticles) * pf_randu(seed, 0);
        for (int x = 0; x < Nparticles; x++) {
            u[x] = u1 + x / ((double)Nparticles);
        }
    }
}

__kernel void find_index_kernel(__global double *arrayX,
                                __global double *arrayY,
                                __global double *CDF,
                                __global double *u,
                                __global double *xj,
                                __global double *yj,
                                __global double *weights,
                                int Nparticles) {
    int j = get_global_id(0);
    if (j >= Nparticles)
        return;

    int i = pf_findIndex(CDF, Nparticles, u[j]);
    if (i == -1)
        i = Nparticles - 1;

    xj[j] = arrayX[i];
    yj[j] = arrayY[i];
    weights[j] = 1.0 / ((double)Nparticles);
}

#endif

